#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long minAbs = LLONG_MAX;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            long long a = llabs(x);
            if (a < minAbs) minAbs = a;
        }
        if (minAbs == 0) {
            printf("-1\n");
        } else {
            printf("%lld\n", minAbs - 1);
        }
    }
    return 0;
}

