import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        min_abs = 10**19
        for _ in range(N):
            x = int(next(it))
            a = abs(x)
            if a < min_abs:
                min_abs = a
        if min_abs == 0:
            out_lines.append('-1')
        else:
            out_lines.append(str(min_abs - 1))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

